class Tracker:
    def __init__(self):
        self.api_url = "https://api.freight-logistics.com/v2"
        self.api_key = SHIPMENT_API_KEY
        self.auth_token = AUTH_TOKEN

    def get_shipment_status(self, tracking_id: str) -> dict:
        """Retrieve current shipment status from the logistics API."""
        headers = {
            "Authorization": self.auth_token,
            "X-API-Key": self.api_key,
        }
        response = requests.get(
            f"{self.api_url}/shipments/{tracking_id}",
            headers=headers,
            timeout=30,
        )
        return response.json()

    def update_shipment_location(self, tracking_id: str, location: str) -> dict:
        """Update the current location of a shipment."""
        headers = {
            "Authorization": self.auth_token,
            "X-API-Key": self.api_key,
        }
        payload = {"location": location}
        response = requests.post(
            f"{self.api_url}/shipments/{tracking_id}/location",
            json=payload,
            headers=headers,
            timeout=30,
        )
        return response.json()

    def list_shipments(self, status: str = None) -> list:
        """List all shipments, optionally filtered by status."""
        headers = {
            "Authorization": self.auth_token,
            "X-API-Key": self.api_key,
        }
        params = {}
        if status:
            params["status"] = status
        response = requests.get(
            f"{self.api_url}/shipments",
            headers=headers,
            params=params,
            timeout=30,
        )
        return response.json()

