import json
import requests

class WarehouseSync:
    """Synchronize shipment data with the central warehouse system."""

    def __init__(self, base_url: str = "https://api.freight-logistics.com/v2"):
        self.base_url = base_url
        self.session = requests.Session()

    def fetch_pending_syncs(self) -> list:
        """Retrieve list of shipments pending warehouse sync."""
        response = self.session.get(f"{self.base_url}/warehouse/pending")
        response.raise_for_status()
        return response.json().get("pending", [])

    def sync_shipment(self, shipment_id: str, data: dict) -> dict:
        """Push a single shipment update to warehouse."""
        payload = {"shipment_id": shipment_id, "data": data}
        response = self.session.post(
            f"{self.base_url}/warehouse/sync",
            json=payload,
        )
        response.raise_for_status()
        return response.json()

    def batch_sync(self, syncs: list) -> dict:
        """Batch sync multiple shipment updates."""
        results = {"success": [], "failed": []}
        for item in syncs:
            try:
                result = self.sync_shipment(item["shipment_id"], item["data"])
                results["success"].append(item["shipment_id"])
            except Exception as e:
                results["failed"].append({"shipment_id": item["shipment_id"], "error": str(e)})
        return results

    def get_sync_status(self, shipment_id: str) -> dict:
        """Check the sync status for a specific shipment."""
        response = self.session.get(
            f"{self.base_url}/warehouse/status/{shipment_id}",
        )
        response.raise_for_status()
        return response.json()
